(async () => {
  const minLikes = 100;
  const searchCount = { found: 0, skipped: 0, error: 0 };
  let targetUsername = null;
  let statusUrl = null;
  const articles = Array.from(document.querySelectorAll("article"));
  for (const article of articles) {
    try {
      const likeBtn = article.querySelector("[data-testid=\"like\"]");
      if (!likeBtn) { searchCount.skipped++; continue; }
      const likeSpan = likeBtn.querySelector("span");
      const likeCountText = likeSpan?.textContent || "0";
      const likeCount = parseInt(likeCountText.replace(/[^0-9]/g, "")) || 0;
      if (likeCount < minLikes) { searchCount.skipped++; continue; }
      const followBtn = article.querySelector("[data-testid=\"follow\"]") || article.querySelector("[data-testid=\"unfollow\"]");
      const isFollowing = followBtn?.textContent?.includes("Following") || followBtn?.textContent?.includes("フォロー中");
      if (isFollowing) { searchCount.skipped++; continue; }
      const isLiked = likeBtn.getAttribute("aria-pressed") === "true";
      if (isLiked) { searchCount.skipped++; continue; }
      const userNameEl = article.querySelector("[data-testid=\"User-Name\"]");
      if (userNameEl) {
        const userLink = userNameEl.querySelector("a[href^=\"/\"]") || userNameEl.closest("div")?.querySelector("a[href^=\"/\"]");
        if (userLink) {
          const href = userLink.getAttribute("href");
          const match = href.match(/^\/([^\/\?]+)/);
          if (match && match[1] && !match[1].includes("status") && !match[1].includes("hashtag")) {
            targetUsername = match[1];
          }
        }
      }
      if (!targetUsername) {
        const userLinks = article.querySelectorAll("a[href^=\"/\"]");
        for (const link of userLinks) {
          const href = link.getAttribute("href");
          const text = link.textContent || "";
          if (href && href.startsWith("/") && !href.includes("/status/") && !href.includes("/hashtag/") && !href.includes("/search") && !href.includes("/i/") && !href.includes("/explore") && !href.includes("/photo/") && !href.includes("/video/") && !href.includes("/analytics")) {
            const match = href.match(/^\/([^\/\?]+)/);
            if (match && match[1] && match[1].length > 0 && (text.includes("@") || /^[a-zA-Z0-9_]+$/.test(match[1]))) {
              targetUsername = match[1];
              break;
            }
          }
        }
      }
      const statusLink = article.querySelector("a[href*=\"/status/\"]");
      if (statusLink) {
        const href = statusLink.getAttribute("href");
        if (href && href.includes("/status/")) {
          statusUrl = href.startsWith("http") ? href : `https://x.com${href}`;
        }
      }
      if (targetUsername && statusUrl && statusLink) {
        searchCount.found++;
        window.__targetUsername = targetUsername;
        window.__targetStatusUrl = statusUrl;
        const targetArticle = article;
        statusLink.click();
        let waitCount = 0;
        const maxWaitCount = 40;
        while (waitCount < maxWaitCount) {
          if (!targetArticle.isConnected) {
            return { didAction: true, reason: `found and navigated to target post`, stats: searchCount, username: targetUsername, statusUrl: statusUrl };
          }
          await new Promise(r => setTimeout(r, 500));
          waitCount++;
        }
        return { didAction: false, reason: "article element did not disappear after click" };
      }
    } catch (e) { searchCount.error++; }
  }

})()

(async () => {
  let likeBtn = null;
  let unlikeBtn = null;
  const article = document.querySelector("article");
  if (article) {
    likeBtn = article.querySelector("[data-testid=\"like\"]");
    unlikeBtn = article.querySelector("[data-testid=\"unlike\"]");
  }
  if (!likeBtn && !unlikeBtn) {
    likeBtn = document.querySelector("[data-testid=\"like\"]");
    unlikeBtn = document.querySelector("[data-testid=\"unlike\"]");
  }
  if (unlikeBtn) { return { didAction: false, reason: "already liked" }; }
  if (!likeBtn) { return { didAction: false, reason: "like button not found" }; }
  likeBtn.click();
  await new Promise(r => setTimeout(r, 1000));
  const unlikeBtnAfter = article ? article.querySelector("[data-testid=\"unlike\"]") : document.querySelector("[data-testid=\"unlike\"]");
  if (!unlikeBtnAfter) { return { didAction: false, reason: "like failed" }; }
  return { didAction: true, reason: "liked the post" };
})()
